int longestValidParentheses(char* s) {
    int n = (int)strlen(s);
    int* st = (int*)malloc((n + 2) * sizeof(int));
    int top = 0;
    st[top++] = -1;
    int best = 0;
    for (int i = 0; s[i]; i++) {
        if (s[i] == '(') st[top++] = i;
        else {
            top--;
            if (top == 0) st[top++] = i;
            else {
                int len = i - st[top - 1];
                if (len > best) best = len;
            }
        }
    }
    free(st);
    return best;
}
